dtsPropsFor.Button:
/** Visual style. */
  variant?: 'primary' | 'secondary' | 'ghost';
  /** Height and padding preset. */
  size?: 'sm' | 'md';
  className?: string;
  children?: React.ReactNode;
  disabled?: boolean;
  type?: 'button' | 'submit' | 'reset';
  onClick?: React.MouseEventHandler<HTMLButtonElement>;
  /** Also accepts all standard <button> attributes. A ButtonLink export with the same variant/size renders an anchor instead. */

dtsPropsFor.Card:
className?: string;
  children?: React.ReactNode;
  /** Also accepts standard <div> attributes. Compose with the CardTitle and CardText exports for the heading and body text. */

dtsPropsFor.Container:
/** Max-width preset. */
  size?: 'default' | 'wide' | 'narrow';
  className?: string;
  children?: React.ReactNode;

dtsPropsFor.Section:
/** Small label above the title. */
  eyebrow?: string;
  /** Section heading. */
  title?: string;
  /** Supporting paragraph under the title. */
  description?: string;
  className?: string;
  children?: React.ReactNode;

dtsPropsFor.SectionHeading:
eyebrow?: string;
  title?: string;
  description?: string;
  className?: string;

dtsPropsFor.CheckList:
/** List entries. */
  items: readonly string[];
  /** Marker style: check (included), cross (excluded), dot (neutral). */
  tone?: 'check' | 'cross' | 'dot';
  className?: string;

dtsPropsFor.PageHero:
eyebrow: string;
  title: string;
  /** Substring of `title` to render in the gold gradient accent. */
  highlight?: string;
  description: string;
  /** Primary CTA link. Pass null to hide; defaults to the site primary CTA. */
  primaryAction?: { href: string; label: string } | null;
  /** Optional secondary CTA link. */
  secondaryAction?: { href: string; label: string };
  note?: string;
  children?: React.ReactNode;

dtsPropsFor.ClosingCta:
/** Heading. Defaults to "Start with a free workflow review." */
  title?: string;
  /** Reassurance line under the heading. Defaults to the site response commitment. */
  reassurance?: string;
